apiVersion: v1
data:
  rollback.sh: |
    #!/usr/bin/env bash
    # rollback.sh — revert spark-pi namespace to original defaults
    #
    # Current non-default settings detected:
    #   - spark-pi-role: 'pods' resource added (not in original spark-rbac.yaml)
    #   - spark-master Deployment: image apache/spark:3.5.3, replicas 1,
    #       cpu_req=200m/mem_req=512Mi, cpu_lim=500m/mem_lim=1Gi (applied values)
    #   - spark-worker Deployment: same resources + SPARK_WORKER_MEMORY=1G/SPARK_WORKER_CORES=1
    #
    # DO NOT run this script until the change window is approved.
    # It will undo all configuration that the cluster currently depends on.

    set -euo pipefail
    NAMESPACE="spark-pi"

    echo "[rollback] Restoring spark-pi-role to original permissions (remove 'pods')..."
    kubectl -n "${NAMESPACE}" patch role spark-pi-role --type=json -p '[
      {
        "op": "replace",
        "path": "/rules/0/resources",
        "value": ["services", "configmaps", "persistentvolumeclaims"]
      }
    ]'

    echo "[rollback] Restoring spark-master Deployment to original defaults..."
    kubectl -n "${NAMESPACE}" patch deployment spark-master --type=strategic -p '{
      "spec": {
        "replicas": 1,
        "template": {
          "spec": {
            "containers": [{
              "name": "spark-master",
              "image": "apache/spark:3.5.3",
              "resources": {
                "requests": {"cpu": "200m", "memory": "512Mi"},
                "limits":   {"cpu": "500m", "memory": "1Gi"}
              }
            }]
          }
        }
      }
    }'

    echo "[rollback] Restoring spark-worker Deployment to original defaults..."
    kubectl -n "${NAMESPACE}" patch deployment spark-worker --type=strategic -p '{
      "spec": {
        "replicas": 1,
        "template": {
          "spec": {
            "containers": [{
              "name": "spark-worker",
              "image": "apache/spark:3.5.3",
              "resources": {
                "requests": {"cpu": "200m", "memory": "512Mi"},
                "limits":   {"cpu": "500m", "memory": "1Gi"}
              }
            }]
          }
        }
      }
    }'

    echo "[rollback] Waiting for rollout to complete..."
    kubectl -n "${NAMESPACE}" rollout status deployment/spark-master --timeout=120s
    kubectl -n "${NAMESPACE}" rollout status deployment/spark-worker --timeout=120s

    echo "[rollback] Done. spark-pi namespace is back to original defaults."
